        for(int i=0;i<N;i++) prefA[i+1]=prefA[i]+(A[i]=='1');
        for(int i=0;i<N;i++) prefB[i+1]=prefB[i]+(B[i]=='1');
        const long long INF = (1LL<<60);
        vector<vector<long long>> dp(N+1, vector<long long>(N+1, INF));
        dp[0][0]=0;
        for(int i=0;i<=N;i++){
            for(int j=0;j<=N;j++){
                long long cur=dp[i][j];
                if(cur==INF) continue;
                if(i<N){
                    long long add = (A[i]=='0') ? (prefA[i]+prefB[j]) : 0;
                    dp[i+1][j]=min(dp[i+1][j], cur+add);
                }
                if(j<N){
                    long long add = (B[j]=='0') ? (prefA[i]+prefB[j]) : 0;
                    dp[i][j+1]=min(dp[i][j+1], cur+add);
                }
            }
        }
        cout<<dp[N][N]<<"\n";
    }
    return 0;
}

