    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String A = br.readLine().trim();
            String B = br.readLine().trim();
            int[] prefA = new int[N+1];
            int[] prefB = new int[N+1];
            for (int i = 0; i < N; i++) prefA[i+1] = prefA[i] + (A.charAt(i)=='1' ? 1 : 0);
            for (int i = 0; i < N; i++) prefB[i+1] = prefB[i] + (B.charAt(i)=='1' ? 1 : 0);
            long INF = Long.MAX_VALUE/4;
            long[][] dp = new long[N+1][N+1];
            for (int i = 0; i <= N; i++) Arrays.fill(dp[i], INF);
            dp[0][0] = 0;
            for (int i = 0; i <= N; i++) {
                for (int j = 0; j <= N; j++) {
                    long cur = dp[i][j];
                    if (cur == INF) continue;
                    if (i < N) {
                        long add = (A.charAt(i)=='0') ? (prefA[i] + prefB[j]) : 0;
                        dp[i+1][j] = Math.min(dp[i+1][j], cur + add);
                    }
                    if (j < N) {
                        long add = (B.charAt(j)=='0') ? (prefA[i] + prefB[j]) : 0;
                        dp[i][j+1] = Math.min(dp[i][j+1], cur + add);
                    }
                }
            }
            out.append(dp[N][N]).append('\n');
        }
        System.out.print(out.toString());
    }
}

