import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        A = next(it).strip()
        B = next(it).strip()
        prefA = [0]*(N+1)
        prefB = [0]*(N+1)
        for i,ch in enumerate(A):
            prefA[i+1] = prefA[i] + (ch=='1')
        for i,ch in enumerate(B):
            prefB[i+1] = prefB[i] + (ch=='1')
        INF = 10**18
        dp = [[INF]*(N+1) for _ in range(N+1)]
        dp[0][0] = 0
        for i in range(N+1):
            for j in range(N+1):
                cur = dp[i][j]
                if cur==INF:
                    continue
                if i<N:
                    add = (prefA[i] + prefB[j]) if A[i]=='0' else 0
                    if cur+add < dp[i+1][j]:
                        dp[i+1][j] = cur+add
                if j<N:
                    add = (prefA[i] + prefB[j]) if B[j]=='0' else 0
                    if cur+add < dp[i][j+1]:
                        dp[i][j+1] = cur+add
        out_lines.append(str(dp[N][N]))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

