const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const A = input[idx++];
  const B = input[idx++];
  const prefA = new Array(N + 1).fill(0);
  const prefB = new Array(N + 1).fill(0);
  for (let i = 0; i < N; i++) prefA[i + 1] = prefA[i] + (A[i] === '1' ? 1 : 0);
  for (let i = 0; i < N; i++) prefB[i + 1] = prefB[i] + (B[i] === '1' ? 1 : 0);
  const INF = 1n << 60n;
  const dp = Array.from({ length: N + 1 }, () => new Array(N + 1).fill(INF));
  dp[0][0] = 0n;
  for (let i = 0; i <= N; i++) {
    for (let j = 0; j <= N; j++) {
      const cur = dp[i][j];
      if (cur === INF) continue;
      if (i < N) {
        const add = A[i] === '0' ? BigInt(prefA[i] + prefB[j]) : 0n;
        const val = cur + add;
        if (val < dp[i + 1][j]) dp[i + 1][j] = val;
      }
      if (j < N) {
        const add = B[j] === '0' ? BigInt(prefA[i] + prefB[j]) : 0n;
        const val = cur + add;
        if (val < dp[i][j + 1]) dp[i][j + 1] = val;
      }
    }
  }
  results.push(dp[N][N].toString());
}
